+/// Fold equality compares against floating min/max-like select patterns.
+///
+/// This handles:
+///   fcmp oeq/ueq (select (fcmp Pred X, K), X, K), C
+///   fcmp oeq/ueq (select (fcmp Pred X, K), K, X), C
+///
+/// when the select is recognized as an fmaxnum/fminnum-like operation and one
+/// operand is the constant bound K. The result can be expressed as a
+/// direct comparison against X based on the relation between C and K:
+///
+///   fmaxnum-like:
+///     C > K  -> X == C
+///     C == K -> X <= K
+///
+///   fminnum-like:
+///     C < K  -> X == C
+///     C == K -> X >= K
+///
+static Instruction *foldFCmpEqWithMinMaxLikeSelect(FCmpInst &I,
+                                                   Instruction *LHSI,
+                                                   Constant *RHSC,
+                                                   InstCombinerImpl &CI) {
+
+  const FCmpInst::Predicate Pred = I.getPredicate();
+  if (Pred != FCmpInst::FCMP_OEQ && Pred != FCmpInst::FCMP_UEQ)
+    return nullptr;
+
+  auto *SI = dyn_cast<SelectInst>(LHSI);
+  const APFloat *C;
+  if (!SI || !match(RHSC, m_APFloat(C)))
+    return nullptr;
+
+  Value *A, *B;
+  SelectPatternResult SPR = matchSelectPattern(SI, A, B);
+  if (SPR.Flavor != SPF_FMAXNUM && SPR.Flavor != SPF_FMINNUM)
+    return nullptr;
+
+  if (SPR.NaNBehavior == SPNB_NA)
+    return nullptr;
+
+  bool Ordered = FCmpInst::isOrdered(Pred);
+  auto getPred = [&](FCmpInst::Predicate OrderedPred,
+                     FCmpInst::Predicate UnorderedPred,
+                     bool IsEqualCase) -> FCmpInst::Predicate {
+    switch (SPR.NaNBehavior) {
+    case SPNB_RETURNS_NAN:
+      return Ordered ? OrderedPred : UnorderedPred;
+
+    case SPNB_RETURNS_OTHER:
+    case SPNB_RETURNS_ANY:
+      // Different vs equal case matters here
+      return IsEqualCase ? UnorderedPred : OrderedPred;
+
+    default:
+      llvm_unreachable("Unsupported NaN behavior");
+    }
+  };
+
+  Constant *CmpBoundC;
+  if (!match(B, m_Constant(CmpBoundC)))
+    return nullptr;
+
+  // Supports only splat vector constants
+  auto *Val = CmpBoundC->getType()->isVectorTy() ? CmpBoundC->getSplatValue()
+                                                 : CmpBoundC;
+  auto *CmpBoundFP = dyn_cast_or_null<ConstantFP>(Val);
+  if (!CmpBoundFP)
+    return nullptr;
+
+  const SimplifyQuery Q = CI.getSimplifyQuery().getWithInstruction(&I);
+  auto CreateFCmp = [&](FCmpInst::Predicate NewPred) -> FCmpInst * {
+    auto *NewCmp = new FCmpInst(NewPred, A, RHSC);
+    FastMathFlags FMF;
+    if (isKnownNeverNaN(A, Q) && isKnownNeverNaN(RHSC, Q))
+      FMF.setNoNaNs();
+    if (isKnownNeverInfinity(A, Q) && isKnownNeverInfinity(RHSC, Q))
+      FMF.setNoInfs();
+
+    NewCmp->setFastMathFlags(FMF);
+    return NewCmp;
+  };
+
+  APFloat::cmpResult CmpVsBound = C->compare(CmpBoundFP->getValueAPF());
+  if (SPR.Flavor == SPF_FMAXNUM) {
+    // max(X, K) == C:
+    //  C > K  -> X == C
+    //  C == K -> X <= K
+
+    if (CmpVsBound == APFloat::cmpGreaterThan)
+      return CreateFCmp(getPred(FCmpInst::FCMP_OEQ, FCmpInst::FCMP_UEQ,
+                                /*IsEqualCase=*/false));
+
+    if (CmpVsBound == APFloat::cmpEqual)
+      return CreateFCmp(getPred(FCmpInst::FCMP_OLE, FCmpInst::FCMP_ULE,
+                                /*IsEqualCase=*/true));
+
+    return nullptr;
+  }
+
+  // min(X, K) == C:
+  //   C < K  -> X == C
+  //   C == K -> X >= K
+
+  if (CmpVsBound == APFloat::cmpLessThan)
+    return CreateFCmp(
+        getPred(FCmpInst::FCMP_OEQ, FCmpInst::FCMP_UEQ, /*IsEqualCase=*/false));
+
+  if (CmpVsBound == APFloat::cmpEqual)
+    return CreateFCmp(
+        getPred(FCmpInst::FCMP_OGE, FCmpInst::FCMP_UGE, /*IsEqualCase=*/true));
+
+  return nullptr;
+}
+
 /// Returns true if a select that implements a min/max is redundant and
 /// select result can be replaced with its non-constant operand, e.g.,
 ///   select ( (si/ui-to-fp A) <= C ), C, (si/ui-to-fp A)
@@ -9181,6 +9295,10 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
