tests.test_body:
define i1 @fold_fcmp_max_clamp_small_const(double nofpclass(inf) %x) {
  %min_cmp = fcmp olt double %x, 5.000000e+00
  %clamp = select i1 %min_cmp, double %x, double 5.000000e+00
  %cmp = fcmp nnan ueq double %clamp, 3.000000e+00
  ret i1 %cmp
}

define i1 @fold_fcmp_max_clamp_same_constant(double %x) {
  %min_cmp = fcmp ogt double %x, 5.000000e+00
  %clamp = select i1 %min_cmp, double 5.000000e+00, double %x
  %cmp = fcmp nnan ninf oeq double %clamp, 5.000000e+00
  ret i1 %cmp
}

define <2 x i1> @fold_fcmp_max_clamp_neg_test_vect(<2 x float> %x) {
  %min_cmp = fcmp olt <2 x float> %x, splat (float 5.000000e+00)
  %clamp = select <2 x i1> %min_cmp, <2 x float> %x, <2 x float> splat (float 5.000000e+00)
  %cmp = fcmp nnan ueq <2 x float> %clamp, <float 3.000000e+00, float 2.000000e+00>
  ret <2 x i1> %cmp
}

define i1 @fold_fcmp_min_clamp_same_constant(double %x) {
  %max_cmp = fcmp ult double %x, 2.000000e+00
  %clamp = select i1 %max_cmp, double 2.000000e+00, double %x
  %cmp = fcmp ueq double %clamp, 2.000000e+00
  ret i1 %cmp
}

define float @test_select_fcmp_uitofp_min(i8 %x) {
  %f = uitofp i8 %x to float
  %cmp = fcmp oge float %f, 2.550000e+02
  %sel = select i1 %cmp, float 2.550000e+02, float %f
  ret float %sel
}

define i1 @fold_fcmp_non_minmax_shape(double %x, double %y) {
  %cmp = fcmp ogt double %x, 2.000000e+00
  %clamp = select i1 %cmp, double %x, double %y
  %res = fcmp oeq double %clamp, 5.000000e+00
  ret i1 %res
}

define i1 @fold_fcmp_max_clamp_bigger_const_no_fold(double %x) {
  %min_cmp = fcmp ugt double %x, 5.000000e+00
  %clamp = select i1 %min_cmp, double 5.000000e+00, double %x
  %cmp = fcmp oeq double %clamp, 6.000000e+00
  ret i1 %cmp
}

define i1 @fold_fcmp_min_clamp_big_const(double nofpclass(nan inf) %x) {
  %max_cmp = fcmp ogt double %x, 2.000000e+00
  %clamp = select i1 %max_cmp, double %x, double 2.000000e+00
  %cmp = fcmp oeq double %clamp, 5.000000e+00
  ret i1 %cmp
}

define i1 @fold_fcmp_min_clamp_smaller_const_no_fold(double %x) {
  %max_cmp = fcmp ogt double %x, 2.000000e+00
  %clamp = select i1 %max_cmp, double %x, double 2.000000e+00
  %cmp = fcmp nnan oeq double %clamp, 1.000000e+00
  ret i1 %cmp
}
